+    #[test]
+    fn dataframe_pivot_table_drops_missing_keys_by_default() {
+        let df = DataFrame::from_series(vec![
+            Series::from_values(
+                "row",
+                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
+                vec![
+                    Scalar::Utf8("r1".into()),
+                    Scalar::Null(NullKind::Null),
+                    Scalar::Utf8("r2".into()),
+                    Scalar::Utf8("r1".into()),
+                ],
+            )
+            .unwrap(),
+            Series::from_values(
+                "col",
+                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
+                vec![
+                    Scalar::Utf8("c1".into()),
+                    Scalar::Utf8("c1".into()),
+                    Scalar::Null(NullKind::Null),
+                    Scalar::Null(NullKind::Null),
+                ],
+            )
+            .unwrap(),
+            Series::from_values(
+                "val",
+                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
+                vec![
+                    Scalar::Float64(1.0),
+                    Scalar::Float64(2.0),
+                    Scalar::Float64(3.0),
+                    Scalar::Float64(4.0),
+                ],
+            )
+            .unwrap(),
+        ])
+        .unwrap();
+
+        let pivoted = df.pivot_table("val", "row", "col", "sum").unwrap();
+
+        assert_eq!(
+            pivoted.index.labels(),
+            &[IndexLabel::Utf8("r1".into()), IndexLabel::Utf8("r2".into())]
+        );
+        assert_eq!(pivoted.column_order, vec!["c1".to_owned()]);
+        assert_eq!(
+            pivoted.columns["c1"].values(),
+            &[Scalar::Float64(1.0), Scalar::Null(NullKind::NaN)]
+        );
+    }
